// Index holds pre-built lookup tables over a STIX bundle.
type Index struct {
	ByID           map[string]map[string]interface{}
	Mitigations    map[string]map[string]interface{}
	TechMitigations map[string][]map[string]interface{}
	Parent         map[string]string
}

// NewIndex constructs an Index from a slice of STIX objects.
func NewIndex(objects []map[string]interface{}) *Index {
	idx := &Index{
		ByID:            make(map[string]map[string]interface{}),
		Mitigations:     make(map[string]map[string]interface{}),
		TechMitigations: make(map[string][]map[string]interface{}),
		Parent:          make(map[string]string),
	}

	// R04: dict comprehension â†’ explicit for loop
	for _, o := range objects {
		id, ok := o["id"].(string)
		if ok && len(id) > 0 {
			idx.ByID[id] = o
		}
	}

	// R04: filtered dict comprehension â†’ explicit for loop
	for _, o := range objects {
		if oType, _ := o["type"].(string); oType == "course-of-action" && isLive(o) {
			if id, ok := o["id"].(string); ok && len(id) > 0 {
				idx.Mitigations[id] = o
			}
		}
	}

	// R10: for rel in objects â†’ for _, rel := range objects
	for _, rel := range objects {
		rType, _ := rel["type"].(string)
		if rType != "relationship" {
			continue
		}
		relType, _ := rel["relationship_type"].(string)
		src, _ := rel["source_ref"].(string)
		tgt, _ := rel["target_ref"].(string)

		// R11: src in self.mitigations â†’ explicit map lookup
		if relType == "mitigates" {
			if mit, exists := idx.Mitigations[src]; exists {
				idx.TechMitigations[tgt] = append(idx.TechMitigations[tgt], mit)
			}
		} else if relType == "subtechnique-of" {
			if len(src) > 0 {
				idx.Parent[src] = tgt
			}
		}
	}

	return idx
}

