def annotate(
    self,
    chunks: list[DocumentChunk],
    obj: object,
) -> list[DocumentChunk]:
    meta: dict[str, dict] = {}
    rendered: dict[str, str] = {}
    for study in _iter_studies(obj):
        ps = study.get("protocolSection", {})
        ident = ps.get("identificationModule", {})
        nct_id = ident.get("nctId")
        if not nct_id:
