// renderOneClinicalStudy renders a single ClinicalTrials.gov study as markdown.
func renderOneClinicalStudy(study map[string]interface{}) string {
	ps := getMap(study, "protocolSection")
	ident := getMap(ps, "identificationModule")
	nctID, _ := ident["nctId"].(string)
	if len(nctID) == 0 {
		nctID = "UNKNOWN"
	}
	title, _ := ident["briefTitle"].(string)
	// R11: fallback to officialTitle if briefTitle empty
	if len(title) == 0 {
		title, _ = ident["officialTitle"].(string)
	}

	statusMod := getMap(ps, "statusModule")
	status, _ := statusMod["overallStatus"].(string)

	designMod := getMap(ps, "designModule")
	var phaseList []string
	if pl, ok := designMod["phases"].([]interface{}); ok {
		for _, p := range pl {
			if ps, ok := p.(string); ok {
				phaseList = append(phaseList, ps)
			}
		}
	}
	phases := strings.Join(phaseList, ", ")

	descMod := getMap(ps, "descriptionModule")
	briefRaw, _ := descMod["briefSummary"].(string)
	brief := strings.TrimSpace(briefRaw)
	detailedRaw, _ := descMod["detailedDescription"].(string)
	detailed := strings.TrimSpace(detailedRaw)

	condsMod := getMap(ps, "conditionsModule")
	var conditions []string
	if cl, ok := condsMod["conditions"].([]interface{}); ok {
		for _, c := range cl {
			if cs, ok := c.(string); ok {
				conditions = append(conditions, cs)
			}
		}
	}

	armsMod := getMap(ps, "armsInterventionsModule")
	var interventions []string
	if ivs, ok := armsMod["interventions"].([]interface{}); ok {
		for _, ivRaw := range ivs {
			iv, ok := ivRaw.(map[string]interface{})
			if !ok {
				continue
			}
			itype, _ := iv["type"].(string)
			iname, _ := iv["name"].(string)
			if len(iname) > 0 {
				if len(itype) > 0 {
					interventions = append(interventions, fmt.Sprintf("%s: %s", itype, iname))
				} else {
					interventions = append(interventions, iname)
				}
			}
		}
	}

	eligMod := getMap(ps, "eligibilityModule")
	eligRaw, _ := eligMod["eligibilityCriteria"].(string)
	eligibility := strings.TrimSpace(eligRaw)
	minAge, _ := eligMod["minimumAge"].(string)
	maxAge, _ := eligMod["maximumAge"].(string)
	sex, _ := eligMod["sex"].(string)

	// R08: f-string â†’ fmt.Sprintf
	lines := []string{fmt.Sprintf("# %s %s", nctID, title), ""}
	var meta []string
	if len(status) > 0 {
		meta = append(meta, fmt.Sprintf("**Status:** %s", status))
	}
	if len(phases) > 0 {
		meta = append(meta, fmt.Sprintf("**Phase:** %s", phases))
	}
	if len(conditions) > 0 {
		// R09: conditions[:5]
		lim := conditions
		if len(lim) > 5 {
			lim = lim[:5]
		}
		meta = append(meta, fmt.Sprintf("**Conditions:** %s", strings.Join(lim, ", ")))
	}
	lines = append(lines, meta...)

	if len(brief) > 0 {
		lines = append(lines, "", "## Summary", "", brief)
	}
	if len(detailed) > 0 {
		lines = append(lines, "", "## Detailed Description", "", detailed)
	}
	if len(interventions) > 0 {
		lines = append(lines, "", "## Interventions", "")
		// R09: interventions[:10]
		lim := interventions
		if len(lim) > 10 {
			lim = lim[:10]
		}
		for _, iv := range lim {
			lines = append(lines, fmt.Sprintf("- %s", iv))
		}
	}
	if len(eligibility) > 0 {
		// R04: [p for p in [min_age, max_age] if p] â†’ explicit loop
		var ageParts []string
		for _, p := range []string{minAge, maxAge} {
			if len(p) > 0 {
				ageParts = append(ageParts, p)
			}
		}
		ageStr := strings.Join(ageParts, " to ")
		var eligHeader string
		if len(sex) > 0 || len(ageStr) > 0 {
			eligHeader = fmt.Sprintf("## Eligibility (%s, %s)", sex, ageStr)
		} else {
			eligHeader = "## Eligibility"
		}
		// R09: eligibility[:2000]
		eligTrunc := eligibility
		if len(eligTrunc) > 2000 {
			eligTrunc = eligTrunc[:2000]
		}
		lines = append(lines, "", eligHeader, "", eligTrunc)
	}

	return strings.Join(lines, "\n")
}

