func renderOneCVE(cve map[string]interface{}) string {
	cveID, _ := cve["id"].(string)
	if len(cveID) == 0 {
		cveID = "UNKNOWN"
	}
	// R09: [:10] slice on string â€” convert to runes safely via len check
	publishedRaw, _ := cve["published"].(string)
	published := ""
	if len(publishedRaw) >= 10 {
		published = publishedRaw[:10]
	} else {
		published = publishedRaw
	}
	modifiedRaw, _ := cve["lastModified"].(string)
	modified := ""
	if len(modifiedRaw) >= 10 {
		modified = modifiedRaw[:10]
	} else {
		modified = modifiedRaw
	}
	status, _ := cve["vulnStatus"].(string)

	descs, _ := cve["descriptions"].([]interface{})
	description := enText(descs)
	score, severity := bestCVSS(getMapSafe(cve, "metrics"))

	// R10: for w in cve.get("weaknesses", []) â†’ for _, w := range ...
	var weaknesses []string
	if ws, ok := cve["weaknesses"].([]interface{}); ok {
		for _, wRaw := range ws {
			w, ok := wRaw.(map[string]interface{})
			if !ok {
				continue
			}
			var wDescs []interface{}
			if wd, ok := w["description"].([]interface{}); ok {
				wDescs = wd
			}
			val := enText(wDescs)
			if len(val) > 0 {
				found := false
				for _, existing := range weaknesses {
					if existing == val {
						found = true
						break
					}
				}
				if !found {
					weaknesses = append(weaknesses, val)
				}
			}
		}
	}

	// Triple-nested loop: configurations â†’ nodes â†’ cpeMatch
	var affected []string
	if cfgs, ok := cve["configurations"].([]interface{}); ok {
		for _, cfgRaw := range cfgs {
			cfg, ok := cfgRaw.(map[string]interface{})
			if !ok {
				continue
			}
			nodes, _ := cfg["nodes"].([]interface{})
			for _, nodeRaw := range nodes {
				node, ok := nodeRaw.(map[string]interface{})
				if !ok {
					continue
				}
				cpeMatches, _ := node["cpeMatch"].([]interface{})
				for _, mRaw := range cpeMatches {
					m, ok := mRaw.(map[string]interface{})
					if !ok {
						continue
					}
					vulnerable, _ := m["vulnerable"].(bool)
					// R11: if not m.get("vulnerable") â†’ if !vulnerable
					if !vulnerable {
						continue
					}
					criteria, _ := m["criteria"].(string)
					readable := cpeReadable(criteria, m)
					found := false
					for _, ex := range affected {
						if ex == readable {
							found = true
							break
						}
					}
					if !found {
						affected = append(affected, readable)
					}
				}
			}
		}
	}

	// R04: list comprehension â†’ explicit loop
	var references []string
	if refs, ok := cve["references"].([]interface{}); ok {
		for _, rRaw := range refs {
			r, ok := rRaw.(map[string]interface{})
			if !ok {
				continue
			}
			if u, ok := r["url"].(string); ok && len(u) > 0 {
				references = append(references, u)
			}
		}
	}

	// R08: f-strings â†’ fmt.Sprintf
	lines := []string{fmt.Sprintf("# %s", cveID), ""}
	var meta []string
	if len(status) > 0 {
		meta = append(meta, fmt.Sprintf("**Status:** %s", status))
	}
	if len(published) > 0 {
		meta = append(meta, fmt.Sprintf("**Published:** %s", published))
	}
	if len(modified) > 0 {
		meta = append(meta, fmt.Sprintf("**Last Modified:** %s", modified))
	}
	// R06: score is not None â†’ score != nil (pointer)
	if score != nil {
		sev := ""
		if len(severity) > 0 {
			sev = fmt.Sprintf(" (%s)", severity)
		}
		meta = append(meta, fmt.Sprintf("**CVSS Score:** %v%s", *score, sev))
	}
	if len(weaknesses) > 0 {
		meta = append(meta, fmt.Sprintf("**CWE:** %s", strings.Join(weaknesses, ", ")))
	}
	lines = append(lines, meta...)

	if len(description) > 0 {
		lines = append(lines, "", "## Description", "", description)
	}
	if len(affected) > 0 {
		lines = append(lines, "", "## Affected", "")
		for _, a := range affected {
			lines = append(lines, fmt.Sprintf("- %s", a))
		}
	}
	if len(references) > 0 {
		lines = append(lines, "", "## References", "")
		// R09: references[:10]
		lim := references
		if len(lim) > 10 {
			lim = lim[:10]
		}
		for _, u := range lim {
			lines = append(lines, fmt.Sprintf("- %s", u))
		}
	}
	return strings.Join(lines, "\n")
}

