	allIDs := make([]string, 0, len(toc))
	for _, entry := range toc {
		allIDs = append(allIDs, entry.anchorID)
	}
	// Build index map for O(1) lookup
	idxMap := make(map[string]int, len(allIDs))
	for i, id := range allIDs {
		idxMap[id] = i
	}

	var sections []string

	// R10: for anchor_id, item_num in toc_filtered â†’ for _, entry := range tocFiltered
	for _, entry := range tocFiltered {
		attributeStr := fmt.Sprintf(`id="%s"`, entry.anchorID)
		attrPos := strings.Index(html, attributeStr)
		if attrPos == -1 {
			continue
		}
		tagStart := strings.LastIndex(html[:attrPos], "<")
		posStart := attrPos
		if tagStart != -1 {
			posStart = tagStart
		}

		// R03: try all_ids.index(anchor_id) / except ValueError â†’ map lookup
		idx, ok := idxMap[entry.anchorID]
		if !ok {
			continue
		}

		posEnd := len(html)
		if idx+1 < len(allIDs) {
			nextID := allIDs[idx+1]
			nextAttrStr := fmt.Sprintf(`id="%s"`, nextID)
			nextAttr := strings.Index(html, nextAttrStr)
			if nextAttr != -1 {
				ts := strings.LastIndex(html[:nextAttr], "<")
				if ts > posStart {
					posEnd = ts
				}
			}
		}

		sectionHTML := html[posStart:posEnd]
		var text string
		if opts.InferBoldHeadings {
			sectionHTML = promoteBoldHeadings(sectionHTML, opts.BoldHeadingMaxLen)
			text = toMarkdown(sectionHTML)
		} else {
			text = stripTags(sectionHTML)
		}
		// R11: if not text.strip() â†’ if len(strings.TrimSpace(text)) == 0
		if len(strings.TrimSpace(text)) == 0 {
			continue
		}

		itemName, found := itemNames[entry.itemNum]
		if !found {
			itemName = fmt.Sprintf("Item %s", entry.itemNum)
		}
		// R08: f-string â†’ fmt.Sprintf
